diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index e1923a344179..8bf61127238e 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3957,8 +3957,40 @@ Instruction *InstCombinerImpl::visitOr(BinaryOperator &I) {
           simplifyAndOrWithOpReplaced(Op1, Op0, Constant::getNullValue(Ty),
                                       /*SimplifyOnly*/ false, *this))
     return BinaryOperator::CreateOr(Op0, V);
+  // (X / C) << K | (X % C) -> (X / C) * (2^K - C) + X
+  // where 2^K > C, and the operations don't overflow.
+  // This handles patterns like: (shl (udiv X, C), K) | (urem X, C)
+  Value *ShlOp, *RemOp;
+  const APInt *ShAmt, *DivC, *RemC;
+  // Try matching (shl (udiv X, C), K) | (urem X, C)
+  if ((match(Op0, m_Shl(m_Value(ShlOp), m_APInt(ShAmt))) &&
+       match(Op1, m_URem(m_Value(RemOp), m_APInt(RemC)))) ||
+      (match(Op1, m_Shl(m_Value(ShlOp), m_APInt(ShAmt))) &&
+       match(Op0, m_URem(m_Value(RemOp), m_APInt(RemC))))) {
+    // Check if ShlOp is (udiv X, C)
+    Value *DivOp0, *DivOp1;
+    if (match(ShlOp, m_UDiv(m_Value(DivOp0), m_APInt(DivC)))) {
+      // Check if urem has same dividend and divisor as udiv
+      if (DivOp0 == RemOp && *DivC == *RemC) {
+        APInt B = APInt(RemC->getBitWidth(), 1);
+        B <<= *ShAmt;
+        // Check B > C (otherwise the transformation doesn't help)
+        if (B.ugt(*RemC)) {
+          APInt BMinusC = B - *RemC;
+          // Create the new mul and add: (udiv X, C) * (2^K - C) + X
+          Value *MulC = ConstantInt::get(Ty, BMinusC);
+          Value *Mul = Builder.CreateMul(ShlOp, MulC, "reass.mul");
+          // Check if the udiv is exact (from noundef), propagate nuw
+          if (auto *Div = dyn_cast<BinaryOperator>(ShlOp))
+            if (Div->isExact())
+              cast<BinaryOperator>(Mul)->setHasNoUnsignedWrap();
+          Value *Add = Builder.CreateAdd(Mul, DivOp0, "i");
+          return replaceInstUsesWith(I, Add);
+        }
+      }
+    }
+  }

-  return nullptr;
 }

 /// A ^ B can be specified using other logic ops in a variety of patterns. We

log.expect_optimized_program:
define i32 @fold_add_udiv_urem_to_mul(i32 noundef %val) {
entry:
  %add = mul i32 %val, 3
  ret i32 %add
}
